"use client";
import { useState, useCallback, useRef } from "react";
import dynamic from "next/dynamic";
import { Group, Panel, Separator } from "react-resizable-panels";
import { Plus, FileCode, Eye, MessageSquare, ChevronLeft } from "lucide-react";
import Link from "next/link";
import { ChatPanel } from "./ChatPanel";
import { Preview } from "./Preview";
import { FileTree } from "./FileTree";

const Editor = dynamic(() => import("@monaco-editor/react"), { ssr: false });

interface File { id: string; projectId: string; name: string; path: string; content: string; language: string; createdAt: Date; updatedAt: Date; }
interface Project { id: string; userId: string; name: string; description: string | null; createdAt: Date; updatedAt: Date; }

const LANG_MAP: Record<string, string> = { tsx: "typescript", ts: "typescript", jsx: "javascript", js: "javascript", html: "html", css: "css", json: "json", md: "markdown" };
function getLanguage(fileName: string) { const ext = fileName.split(".").pop() || ""; return LANG_MAP[ext] || "plaintext"; }

export function ProjectEditor({ project, initialFiles }: { project: Project; initialFiles: File[] }) {
  const [files, setFiles] = useState<File[]>(initialFiles);
  const [activeFileId, setActiveFileId] = useState<string | null>(initialFiles[0]?.id || null);
  const [activeTab, setActiveTab] = useState<"editor" | "preview" | "chat">("chat");
  const [isStreaming, setIsStreaming] = useState(false);
  const [chatMessages, setChatMessages] = useState<{ role: string; content: string }[]>([]);
  const [showNewFile, setShowNewFile] = useState(false);
  const [newFileName, setNewFileName] = useState("");
  const editorRef = useRef<any>(null);
  const activeFile = files.find((f) => f.id === activeFileId);

  const updateFileContent = useCallback(async (fileId: string, content: string) => {
    setFiles((prev) => prev.map((f) => (f.id === fileId ? { ...f, content } : f)));
    await fetch(`/api/projects/${project.id}/files/${fileId}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ content }) });
  }, [project.id]);

  const createFile = useCallback(async () => {
    if (!newFileName.trim()) return;
    const path = newFileName.startsWith("/") ? newFileName : `/${newFileName}`;
    const res = await fetch(`/api/projects/${project.id}/files`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ name: newFileName, path, content: "", language: getLanguage(newFileName) }) });
    const file = await res.json();
    setFiles((prev) => [...prev, file]);
    setActiveFileId(file.id); setNewFileName(""); setShowNewFile(false); setActiveTab("editor");
  }, [newFileName, project.id]);

  const deleteFile = useCallback(async (fileId: string) => {
    await fetch(`/api/projects/${project.id}/files/${fileId}`, { method: "DELETE" });
    setFiles((prev) => prev.filter((f) => f.id !== fileId));
    if (activeFileId === fileId) setActiveFileId(files.find((f) => f.id !== fileId)?.id || null);
  }, [project.id, activeFileId, files]);

  const sendMessage = useCallback(async (content: string) => {
    const userMessage = { role: "user", content };
    const newMessages = [...chatMessages, userMessage];
    setChatMessages(newMessages);
    setIsStreaming(true);
    try {
      const res = await fetch(`/api/projects/${project.id}/chat`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ messages: newMessages }) });
      if (!res.ok) { setChatMessages((prev) => [...prev, { role: "assistant", content: "Error: Failed to get response." }]); setIsStreaming(false); return; }
      const reader = res.body?.getReader();
      const decoder = new TextDecoder();
      let assistantContent = "";
      setChatMessages((prev) => [...prev, { role: "assistant", content: "" }]);
      if (reader) { while (true) { const { done, value } = await reader.read(); if (done) break; const text = decoder.decode(value); assistantContent += text; setChatMessages((prev) => { const u = [...prev]; u[u.length - 1] = { role: "assistant", content: assistantContent }; return u; }); } }
    } catch { setChatMessages((prev) => [...prev, { role: "assistant", content: "Error: Connection failed." }]); }
    setIsStreaming(false);
  }, [chatMessages, project.id]);

  const tabs: { key: "editor" | "preview" | "chat"; icon: any; label: string }[] = [
    { key: "chat", icon: MessageSquare, label: "Chat" },
    { key: "editor", icon: FileCode, label: "Code" },
    { key: "preview", icon: Eye, label: "Preview" },
  ];

  return (
    <div className="h-screen flex flex-col bg-[var(--bg-primary)]">
      <header className="h-12 border-b border-[var(--border)] bg-[var(--bg-secondary)] flex items-center px-3 gap-3 shrink-0">
        <Link href="/" className="text-[var(--text-tertiary)] hover:text-[var(--text-primary)] transition-colors p-1 rounded-[var(--radius-sm)] hover:bg-[var(--bg-tertiary)]"><ChevronLeft size={18} /></Link>
        <div className="w-7 h-7 rounded-[var(--radius-md)] bg-gradient-to-br from-indigo-500 via-purple-500 to-pink-500 flex items-center justify-center text-white shadow-sm">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M12 2L2 7L12 12L22 7L12 2Z" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/><path d="M2 17L12 22L22 17" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/><path d="M2 12L12 17L22 12" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
        </div>
        <span className="font-semibold text-sm text-[var(--text-primary)]">{project.name}</span>
        <div className="flex-1" />
        <div className="flex items-center bg-[var(--bg-tertiary)] rounded-[var(--radius-md)] p-0.5 gap-0.5">
          {tabs.map(({ key, icon: Icon, label }) => (
            <button key={key} onClick={() => setActiveTab(key)}
              className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-[var(--radius-sm)] transition-all ${activeTab === key ? "bg-[var(--accent)] text-white shadow-sm shadow-indigo-500/30" : "text-[var(--text-tertiary)] hover:text-[var(--text-secondary)] hover:bg-[var(--bg-elevated)]"}`}>
              <Icon size={13} />{label}
            </button>
          ))}
        </div>
      </header>
      <div className="flex-1 overflow-hidden">
        {activeTab === "chat" ? (
          <Group orientation="horizontal">
            <Panel defaultSize="35%" minSize="25%" maxSize="50%"><ChatPanel messages={chatMessages} onSend={sendMessage} isStreaming={isStreaming} /></Panel>
            <Separator className="w-1 bg-[var(--border)] hover:bg-[var(--accent)]/30 transition-colors cursor-col-resize" />
            <Panel defaultSize="65%"><Preview files={files} /></Panel>
          </Group>
        ) : activeTab === "editor" ? (
          <Group orientation="horizontal">
            <Panel defaultSize="20%" minSize="15%" maxSize="30%">
              <div className="h-full flex flex-col bg-[var(--bg-secondary)] border-r border-[var(--border)]">
                <div className="px-3 py-2.5 border-b border-[var(--border)] flex items-center justify-between">
                  <span className="text-[11px] font-semibold text-[var(--text-tertiary)] uppercase tracking-wider">Explorer</span>
                  <button onClick={() => setShowNewFile(true)} className="p-1 rounded-[var(--radius-sm)] text-[var(--text-tertiary)] hover:text-[var(--text-primary)] hover:bg-[var(--bg-tertiary)] transition-all"><Plus size={14} /></button>
                </div>
                {showNewFile && (
                  <div className="p-2 border-b border-[var(--border)]">
                    <input autoFocus value={newFileName} onChange={(e) => setNewFileName(e.target.value)} onKeyDown={(e) => { if (e.key === "Enter") createFile(); if (e.key === "Escape") setShowNewFile(false); }} placeholder="filename.tsx" className="w-full px-2.5 py-1.5 bg-[var(--bg-tertiary)] border border-[var(--border)] rounded-[var(--radius-sm)] text-xs text-[var(--text-primary)] placeholder-[var(--text-tertiary)] focus:outline-none focus:ring-1 focus:ring-[var(--accent)]/40" />
                  </div>
                )}
                <div className="flex-1 overflow-y-auto"><FileTree files={files} activeFileId={activeFileId} onSelect={setActiveFileId} onDelete={deleteFile} /></div>
              </div>
            </Panel>
            <Separator className="w-1 bg-[var(--border)] hover:bg-[var(--accent)]/30 transition-colors cursor-col-resize" />
            <Panel>
              {activeFile ? (
                <div className="h-full flex flex-col">
                  <div className="h-9 border-b border-[var(--border)] bg-[var(--bg-secondary)] flex items-center px-3 gap-2">
                    <FileCode size={13} className="text-[var(--accent)]" />
                    <span className="text-xs font-medium text-[var(--text-secondary)]">{activeFile.name}</span>
                    <div className="flex-1" />
                    <span className="text-[10px] text-[var(--text-tertiary)] font-mono">{activeFile.language}</span>
                  </div>
                  <div className="flex-1">
                    <Editor height="100%" language={getLanguage(activeFile.name)} value={activeFile.content} theme="vs-dark"
                      onChange={(value) => { if (value !== undefined && activeFileId) updateFileContent(activeFileId, value); }}
                      onMount={(editor) => { editorRef.current = editor; }}
                      options={{ fontSize: 13, fontFamily: "JetBrains Mono, Fira Code, Menlo, monospace", minimap: { enabled: false }, scrollBeyondLastLine: false, automaticLayout: true, tabSize: 2, wordWrap: "on", padding: { top: 16, bottom: 16 }, smoothScrolling: true, cursorBlinking: "smooth", cursorSmoothCaretAnimation: "on", renderLineHighlight: "gutter" }} />
                  </div>
                </div>
              ) : (
                <div className="h-full flex items-center justify-center text-[var(--text-tertiary)]">
                  <div className="text-center"><FileCode size={40} className="mx-auto mb-3 opacity-30" /><p className="text-sm font-medium">No file selected</p><p className="text-xs mt-1">Select a file from the explorer to start editing</p></div>
                </div>
              )}
            </Panel>
          </Group>
        ) : (
          <Preview files={files} />
        )}
      </div>
    </div>
  );
}
