"use client";
import {
  Trash2, FileCode, FileText, FileJson, FileType,
  Palette, FolderOpen, Settings, Package,
} from "lucide-react";

interface FileItem {
  id: string;
  name: string;
  path: string;
  language: string;
}

function getFileConfig(name: string) {
  if (name === "package.json") return { icon: Package, color: "text-green-400" };
  if (name === "tsconfig.json") return { icon: Settings, color: "text-blue-300" };
  if (name.startsWith("tailwind.config")) return { icon: Palette, color: "text-cyan-400" };
  if (name.startsWith("next.config")) return { icon: Settings, color: "text-gray-300" };
  if (name.startsWith("_") && name.endsWith(".tsx")) return { icon: FileCode, color: "text-purple-400" };
  if (name === "index.tsx" || name === "index.ts") return { icon: FolderOpen, color: "text-indigo-400" };
  if (name === "globals.css" || name === "styles.css") return { icon: Palette, color: "text-pink-400" };

  const ext = name.split(".").pop() || "";
  const configs: Record<string, { icon: any; color: string }> = {
    tsx: { icon: FileCode, color: "text-blue-400" },
    ts: { icon: FileCode, color: "text-blue-400" },
    jsx: { icon: FileCode, color: "text-yellow-400" },
    js: { icon: FileCode, color: "text-yellow-400" },
    mjs: { icon: FileCode, color: "text-yellow-300" },
    html: { icon: FileType, color: "text-orange-400" },
    css: { icon: Palette, color: "text-pink-400" },
    json: { icon: FileJson, color: "text-green-400" },
    md: { icon: FileText, color: "text-gray-400" },
  };
  return configs[ext] || { icon: FileText, color: "text-[var(--text-tertiary)]" };
}

export function FileTree({
  files,
  activeFileId,
  onSelect,
  onDelete,
}: {
  files: FileItem[];
  activeFileId: string | null;
  onSelect: (id: string) => void;
  onDelete: (id: string) => void;
}) {
  const dirs: Record<string, FileItem[]> = {};
  for (const file of files) {
    const parts = file.path.split("/").filter(Boolean);
    const dir = parts.length > 1 ? `/${parts.slice(0, -1).join("/")}` : "/";
    if (!dirs[dir]) dirs[dir] = [];
    dirs[dir].push(file);
  }
  const sortedDirs = Object.keys(dirs).sort();

  return (
    <div className="space-y-0.5 py-1">
      {sortedDirs.map((dir) => (
        <div key={dir}>
          {dir !== "/" && (
            <div className="flex items-center gap-1.5 px-2.5 py-1 text-[11px] font-semibold text-[var(--text-tertiary)] uppercase tracking-wider">
              <FolderOpen size={12} />
              <span>{dir.substring(1)}</span>
            </div>
          )}
          <div className={dir !== "/" ? "ml-2" : ""}>
            {dirs[dir].map((file) => {
              const config = getFileConfig(file.name);
              const Icon = config.icon;
              const isActive = activeFileId === file.id;
              return (
                <div
                  key={file.id}
                  onClick={() => onSelect(file.id)}
                  className={`group flex items-center gap-2 px-2.5 py-1.5 rounded-[var(--radius-sm)] cursor-pointer text-[13px] transition-all ${
                    isActive
                      ? "bg-[var(--accent-bg)] text-[var(--accent)] border border-[var(--accent-border)]"
                      : "text-[var(--text-secondary)] hover:bg-[var(--bg-tertiary)] hover:text-[var(--text-primary)] border border-transparent"
                  }`}
                >
                  <Icon size={14} className={`shrink-0 ${isActive ? "text-[var(--accent)]" : config.color}`} />
                  <span className="truncate flex-1 font-medium">{file.name}</span>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      onDelete(file.id);
                    }}
                    className="opacity-0 group-hover:opacity-100 p-0.5 rounded hover:bg-red-500/10 text-[var(--text-tertiary)] hover:text-[var(--error)] transition-all"
                  >
                    <Trash2 size={12} />
                  </button>
                </div>
              );
            })}
          </div>
        </div>
      ))}
    </div>
  );
}
